final:
module top_module(
  input empty,
  input ge2_free,
  input ge3_free,
  input [1:0] input_tm_cnt,
  output reg [4:0] cnt_dec
);always @(*) begin
    if (empty) begin
      cnt_dec = input_tm_cnt[1:0];
    end else if (ge3_free && (input_tm_cnt == 2'b11)) begin
      cnt_dec = 2;
    end else if (ge2_free && (input_tm_cnt >= 2)) begin
      cnt_dec = 1;
    end else if (input_tm_cnt >= 1) begin
      cnt_dec = 0;
    end else begin
      cnt_dec = 5'b11111;
    end
  end

endmodule
